#nullable enable // autogenerated

using System.Collections.Generic;
using System.Diagnostics.CodeAnalysis;
using System.Linq;
using MVZ2.Metas;
using MVZ2.Modding;
using MVZ2.TalkData;
using MVZ2Logic.Localization;
using PVZEngine;
using UnityEngine;

namespace MVZ2.Managers
{
    public partial class ResourceManager : MonoBehaviour
    {
        public OptionItemMeta? GetOptionItemMeta(NamespaceID? id)
        {
            if (!NamespaceID.IsValid(id))
                return null;
            var modResource = GetModResource(id.SpaceName);
            if (modResource == null || modResource.OptionMetaList == null)
                return null;
            return modResource.OptionMetaList.items.FirstOrDefault(i => i.ID == id.Path);
        }
        public NamespaceID[] GetAllOptionItemsID()
        {
            List<NamespaceID> idList = new List<NamespaceID>();
            foreach (var resource in modResources)
            {
                if (resource == null || resource.OptionMetaList == null)
                    continue;
                foreach (var item in resource.OptionMetaList.items)
                {
                    idList.Add(new NamespaceID(resource.Namespace, item.ID));
                }
            }
            return idList.ToArray();
        }
    }
}
